class Solution:
    def totalNQueens(self, n):
        from itertools import permutations
        count = 0
        for perm in permutations(range(n)):
            ok = True
            for i in range(n):
                for j in range(i + 1, n):
                    if abs(perm[i] - perm[j]) == j - i:
                        ok = False
                        break
                if not ok:
                    break
            if ok:
                count += 1
        return count

